package checkpoint

import (
	"encoding/json"
	"sort"
	"strings"
	"time"

	"github.com/jcleira/entire-local/pkg/git"
)

type Loader struct {
	reader *git.Reader
}

func NewLoader(reader *git.Reader) *Loader {
	return &Loader{reader: reader}
}

func (l *Loader) ListCheckpoints() ([]CheckpointSummary, error) {
	shards, err := l.reader.ListShards()
	if err != nil {
		return nil, err
	}

	var summaries []CheckpointSummary

	for _, shard := range shards {
		rests, err := l.reader.ListCheckpointRests(shard)
		if err != nil {
			continue
		}

		for _, rest := range rests {
			id := shard + rest
			summary, err := l.loadSummary(id, shard, rest)
			if err != nil {
				continue
			}
			summaries = append(summaries, *summary)
		}
	}

	sort.Slice(summaries, func(i, j int) bool {
		return summaries[i].CreatedAt.After(summaries[j].CreatedAt)
	})

	return summaries, nil
}

func (l *Loader) LoadCheckpoint(id string) (*Checkpoint, error) {
	shard := Shard(id)
	rest := Rest(id)
	prefix := shard + "/" + rest

	metaJSON, err := l.reader.ReadFile(prefix + "/metadata.json")
	if err != nil {
		return nil, err
	}

	var meta Metadata
	if err := json.Unmarshal([]byte(metaJSON), &meta); err != nil {
		return nil, err
	}

	var sessionMeta SessionMetadata
	sessionJSON, err := l.reader.ReadFile(prefix + "/0/metadata.json")
	if err == nil {
		_ = json.Unmarshal([]byte(sessionJSON), &sessionMeta)
	}

	prompt, _ := l.reader.ReadFile(prefix + "/0/prompt.txt")
	context, _ := l.reader.ReadFile(prefix + "/0/context.md")
	diff, _ := l.reader.ReadFile(prefix + "/0/diff.patch")
	plan, _ := l.reader.ReadFile(prefix + "/0/plan.md")

	return &Checkpoint{
		Metadata: meta,
		Session:  sessionMeta,
		Prompt:          prompt,
		Context:         context,
		Diff:            diff,
		Plan:            plan,
	}, nil
}

func (l *Loader) LoadTranscript(id string) ([]TranscriptEntry, error) {
	shard := Shard(id)
	rest := Rest(id)

	content, err := l.reader.ReadFile(shard + "/" + rest + "/0/full.jsonl")
	if err != nil {
		return nil, err
	}

	return ParseTranscript(content)
}

func (l *Loader) loadSummary(id, shard, rest string) (*CheckpointSummary, error) {
	prefix := shard + "/" + rest

	metaJSON, err := l.reader.ReadFile(prefix + "/metadata.json")
	if err != nil {
		return nil, err
	}

	var meta Metadata
	if err := json.Unmarshal([]byte(metaJSON), &meta); err != nil {
		return nil, err
	}

	createdAt, _ := time.Parse(time.RFC3339, meta.CreatedAt)
	if createdAt.IsZero() {
		createdAt, _ = time.Parse(time.RFC3339Nano, meta.CreatedAt)
	}

	summary := &CheckpointSummary{
		ID:           id,
		CreatedAt:    createdAt,
		Branch:       meta.Branch,
		Agent:        meta.Agent,
		AgentPercent: meta.AgentPercent,
		CommitHash:   meta.CommitHash,
		PlanSlug:     meta.PlanSlug,
	}

	var sessionMeta SessionMetadata
	sessionJSON, err := l.reader.ReadFile(prefix + "/0/metadata.json")
	if err == nil {
		if json.Unmarshal([]byte(sessionJSON), &sessionMeta) == nil {
			summary.TotalTokens = sessionMeta.TotalTokens
			summary.Duration = sessionMeta.Duration
		}
	}

	context, err := l.reader.ReadFile(prefix + "/0/context.md")
	if err == nil {
		summary.Context = context
	}

	diff, err := l.reader.ReadFile(prefix + "/0/diff.patch")
	if err == nil {
		files, adds, dels := parseDiffStats(diff)
		summary.FileCount = files
		summary.Additions = adds
		summary.Deletions = dels
	}

	return summary, nil
}

func Shard(id string) string {
	if len(id) < 2 {
		return id
	}
	return id[:2]
}

func Rest(id string) string {
	if len(id) <= 2 {
		return ""
	}
	return id[2:]
}

func parseDiffStats(diff string) (files, adds, dels int) {
	filesSeen := make(map[string]bool)
	for _, line := range strings.Split(diff, "\n") {
		if strings.HasPrefix(line, "diff --git") {
			parts := strings.Fields(line)
			if len(parts) >= 4 {
				filesSeen[parts[3]] = true
			}
		} else if strings.HasPrefix(line, "+") && !strings.HasPrefix(line, "+++") {
			adds++
		} else if strings.HasPrefix(line, "-") && !strings.HasPrefix(line, "---") {
			dels++
		}
	}
	files = len(filesSeen)
	return
}

