180ŌåÆfunc parseDiffStats(diff string) diffStatsResult {
181ŌåÆ	var result diffStatsResult
182ŌåÆ	if diff == "" {
183ŌåÆ		return result
184ŌåÆ	}
185ŌåÆ
186ŌåÆ	var current *fileDiffStat
187ŌåÆ	for _, line := range strings.Split(diff, "\n") {
