192ŌåÆ			parts := strings.Fields(line)
193ŌåÆ			name := ""
194ŌåÆ			if len(parts) >= 4 {
195ŌåÆ				name = strings.TrimPrefix(parts[3], "b/")
196ŌåÆ			}
197ŌåÆ			current = &fileDiffStat{name: name}
198ŌåÆ		} else if current != nil {
199ŌåÆ			if strings.HasPrefix(line, "+") && !strings.HasPrefix(line, "+++") {
200ŌåÆ				current.add++
201ŌåÆ			} else if strings.HasPrefix(line, "-") && !strings.HasPrefix(line, "---") {
202ŌåÆ				current.del++
203ŌåÆ			}
204ŌåÆ		}
205ŌåÆ	}
206ŌåÆ	if current != nil {
207ŌåÆ		result.files = append(result.files, *current)
208ŌåÆ	}
209ŌåÆ
210ŌåÆ	for _, f := range result.files {
211ŌåÆ		result.totalAdd += f.add
212ŌåÆ		result.totalDel += f.del
213ŌåÆ	}
214ŌåÆ
215ŌåÆ	return result
216ŌåÆ}
