282ŌåÆfunc wordWrap(text string, width int) string {
283ŌåÆ	if width <= 0 {
284ŌåÆ		return text
285ŌåÆ	}
286ŌåÆ	var result strings.Builder
287ŌåÆ	for _, line := range strings.Split(text, "\n") {
288ŌåÆ		if len(line) <= width {
289ŌåÆ			result.WriteString(line + "\n")
290ŌåÆ			continue
291ŌåÆ		}
292ŌåÆ		remaining := line
293ŌåÆ		for len(remaining) > width {
294ŌåÆ			breakAt := width
295ŌåÆ			if idx := strings.LastIndex(remaining[:width], " "); idx > 0 {
296ŌåÆ				breakAt = idx
297ŌåÆ			}
298ŌåÆ			result.WriteString(remaining[:breakAt] + "\n")
299ŌåÆ			remaining = strings.TrimLeft(remaining[breakAt:], " ")
300ŌåÆ		}
301ŌåÆ		if remaining != "" {
302ŌåÆ			result.WriteString(remaining + "\n")
303ŌåÆ		}
304ŌåÆ	}
305ŌåÆ	return strings.TrimRight(result.String(), "\n")
306ŌåÆ}
