 49ŌåÆfunc groupTranscriptEntries(entries []checkpoint.TranscriptEntry) []messageGroup {
 50ŌåÆ	var groups []messageGroup
 51ŌåÆ	var pendingTools []string
 52ŌåÆ	pendingResults := 0
 53ŌåÆ
 54ŌåÆ	flushTools := func() {
 55ŌåÆ		if len(pendingTools) > 0 || pendingResults > 0 {
 56ŌåÆ			groups = append(groups, messageGroup{
 57ŌåÆ				role:    "tools",
 58ŌåÆ				tools:   pendingTools,
 59ŌåÆ				results: pendingResults,
 60ŌåÆ			})
 61ŌåÆ			pendingTools = nil
 62ŌåÆ			pendingResults = 0
 63ŌåÆ		}
 64ŌåÆ	}
 65ŌåÆ
 66ŌåÆ	for _, e := range entries {
 67ŌåÆ		switch {
 68ŌåÆ		case e.Role == "human" || e.Role == "user":
 69ŌåÆ			if e.Content == "" {
 70ŌåÆ				continue
 71ŌåÆ			}
 72ŌåÆ			flushTools()
 73ŌåÆ			ts := ""
 74ŌåÆ			if !e.Timestamp.IsZero() {
 75ŌåÆ				ts = e.Timestamp.Format("3:04 PM")
 76ŌåÆ			}
 77ŌåÆ			groups = append(groups, messageGroup{
 78ŌåÆ				role:    "user",
 79ŌåÆ				content: e.Content,
 80ŌåÆ				ts:      ts,
 81ŌåÆ			})
 82ŌåÆ
 83ŌåÆ		case e.Role == "assistant" && e.ToolName != "":
 84ŌåÆ			pendingTools = append(pendingTools, e.ToolName)
 85ŌåÆ
 86ŌåÆ		case e.Role == "assistant":
 87ŌåÆ			if e.Content == "" {
 88ŌåÆ				continue
 89ŌåÆ			}
 90ŌåÆ			flushTools()
 91ŌåÆ			ts := ""
 92ŌåÆ			if !e.Timestamp.IsZero() {
 93ŌåÆ				ts = e.Timestamp.Format("3:04 PM")
 94ŌåÆ			}
 95ŌåÆ			groups = append(groups, messageGroup{
 96ŌåÆ				role:    "assistant",
 97ŌåÆ				content: e.Content,
 98ŌåÆ				ts:      ts,
 99ŌåÆ			})
100ŌåÆ
101ŌåÆ		case e.Type == "tool_result":
102ŌåÆ			pendingResults++
103ŌåÆ
104ŌåÆ		default:
105ŌåÆ			if e.Content != "" {
106ŌåÆ				flushTools()
107ŌåÆ				groups = append(groups, messageGroup{
108ŌåÆ					role:    "other",
109ŌåÆ					content: e.Content,
110ŌåÆ				})
111ŌåÆ			}
112ŌåÆ		}
113ŌåÆ	}
114ŌåÆ	flushTools()
115ŌåÆ	return groups
116ŌåÆ}
