171ŌåÆfunc parseDiffStats(diff string) (files, adds, dels int) {
172ŌåÆ	filesSeen := make(map[string]bool)
173ŌåÆ	for _, line := range strings.Split(diff, "\n") {
174ŌåÆ		if strings.HasPrefix(line, "diff --git") {
175ŌåÆ			parts := strings.Fields(line)
176ŌåÆ			if len(parts) >= 4 {
177ŌåÆ				filesSeen[parts[3]] = true
178ŌåÆ			}
179ŌåÆ		} else if strings.HasPrefix(line, "+") && !strings.HasPrefix(line, "+++") {
180ŌåÆ			adds++
181ŌåÆ		} else if strings.HasPrefix(line, "-") && !strings.HasPrefix(line, "---") {
182ŌåÆ			dels++
183ŌåÆ		}
184ŌåÆ	}
185ŌåÆ	files = len(filesSeen)
186ŌåÆ	return
187ŌåÆ}
