49ŌåÆfunc computeStreak(activity map[string]int) int {
50ŌåÆ	if len(activity) == 0 {
51ŌåÆ		return 0
52ŌåÆ	}
53ŌåÆ
54ŌåÆ	days := make([]string, 0, len(activity))
55ŌåÆ	for d := range activity {
56ŌåÆ		days = append(days, d)
57ŌåÆ	}
58ŌåÆ	sort.Sort(sort.Reverse(sort.StringSlice(days)))
59ŌåÆ
60ŌåÆ	streak := 1
61ŌåÆ	for i := 1; i < len(days); i++ {
62ŌåÆ		prev, _ := time.Parse("2006-01-02", days[i-1])
63ŌåÆ		curr, _ := time.Parse("2006-01-02", days[i])
64ŌåÆ		if prev.Sub(curr) == 24*time.Hour {
65ŌåÆ			streak++
66ŌåÆ		} else {
67ŌåÆ			break
68ŌåÆ		}
69ŌåÆ	}
70ŌåÆ
71ŌåÆ	return streak
72ŌåÆ}
